function showMessage(e,t,n=null){const s=document.getElementById("messageArea");s.innerHTML=`<div class='message ${t?"success":"error"}'>${e}</div>`,t&&n?setTimeout(()=>{let t=10;s.innerHTML=`\n        <div class='message success'>\n          ${e}<br><br>\n          Redirecting in <span id="countdown">${t}</span>s.\nAccess http://${n} manually if needed\n\n        </div>\n      `;const i=setInterval(()=>{t--,document.getElementById("countdown").textContent=t,t<=0&&(clearInterval(i),window.location.href="http://"+n)},1e3)},5e3):setTimeout(()=>{s.innerHTML=""},5e3)}function formatSize(e){return e<1024?e+" B":e<1048576?(e/1024).toFixed(1)+" KB":(e/1048576).toFixed(1)+" MB"}function formatSizeWithUnit(e){const t=["B","KB","MB","GB","TB"];let n,s=e,i=0;for(;s>=1024&&i<t.length-1;)s/=1024,i++;return n=0===i?s:s.toFixed(2),`${n} ${t[i]} `}(function(){for(var e=location.pathname.split("/").pop()||"index.html",t=document.querySelectorAll(".menu a"),n=0;n<t.length;n++)t[n].getAttribute("href").replace("./","")===e&&t[n].classList.add("active")})();